744	        match self {
745	            Self::Default(route) => Fallback::Default(route),
746	            Self::Service(route) => Fallback::Service(route),
747	            Self::BoxedHandler(handler) => Fallback::Service(handler.into_route(state)),
748	        }
749	    }
