753	            Self::Default(route) | Self::Service(route) => route.oneshot_inner_owned(req),
754	            Self::BoxedHandler(handler) => {
755	                let route = handler.into_route(state);
756	                route.oneshot_inner_owned(req)
757	            }
758	        }
759	    }
