29	/// Serve the service with the supplied listener.
30	///
31	/// This method of running a service is intentionally simple and doesn't support much configuration.
32	/// hyper's default configuration applies (including [timeouts]); use hyper or hyper-util if you
33	/// need more control. You can supply a custom [`Executor`] via [`Serve::with_executor`] to
34	/// control how connection tasks are spawned.
35	///
36	/// It supports both HTTP/1 as well as HTTP/2.
37	///
38	/// # Examples
39	///
40	/// Serving a [`Router`]:
41	///
42	/// ```
43	/// use axum::{Router, routing::get};
44	///
45	/// # async {
46	/// let router = Router::new().route("/", get(|| async { "Hello, World!" }));
47	///
48	/// let listener = tokio::net::TcpListener::bind("0.0.0.0:3000").await.unwrap();
49	/// axum::serve(listener, router).await;
50	/// # };
51	/// ```
52	///
53	/// See also [`Router::into_make_service_with_connect_info`].
54	///
55	/// Serving a [`MethodRouter`]:
56	///
57	/// ```
58	/// use axum::routing::get;
59	///
60	/// # async {
61	/// let router = get(|| async { "Hello, World!" });
